   181→            <div class="irrational-name" id="name">圆周率</div>
   182→            <div class="irrational-value" id="value">3.14159265358979323846...</div>
   183→        </div>
   184→
   185→        <div class="controls">
   186→            <div class="precision-control">
   187→                <label for="precision">小数位数：</label>
   188→                <select id="precision">
   189→                    <option value="5">5 位</option>
   190→                    <option value="10">10 位</option>
   191→                    <option value="20" selected>20 位</option>
   192→                    <option value="50">50 位</option>
   193→                    <option value="100">100 位</option>
   194→                    <option value="500">500 位</option>
   195→                    <option value="1000">1000 位</option>
   196→                </select>
   197→            </div>
   198→            <button class="generate-btn" onclick="generate()">生成新的无理数</button>
   199→        </div>
   200→
   201→        <div class="history">
   202→            <h3>历史记录（点击可查看）</h3>
   203→            <div class="history-list" id="historyList"></div>
   204→        </div>
   205→
   206→        <div class="info">
   207→            <strong>无理数小知识：</strong> 无理数是指不能表示为两个整数之比的实数。它们的小数部分是无限且不循环的，如 π、e 和 √2 等。
   208→        </div>
