   211→    <script>
   212→        // 无理数数据库
   213→        const irrationals = [
   214→            {
   215→                symbol: 'π',
   216→                name: '圆周率',
   217→                nameEn: 'Pi',
   218→                value: Math.PI,
   219→                description: '圆的周长与直径之比'
   220→            },
   221→            {
   222→                symbol: 'e',
   223→                name: '自然常数',
   224→                nameEn: "Euler's number",
   225→                value: Math.E,
   226→                description: '自然对数的底数'
   227→            },
   228→            {
   229→                symbol: '√2',
   230→                name: '平方根二',
   231→                nameEn: 'Square root of 2',
   232→                value: Math.SQRT2,
   233→                description: '边长为1的正方形对角线长度'
   234→            },
   235→            {
   236→                symbol: '√3',
   237→                name: '平方根三',
   238→                nameEn: 'Square root of 3',
   239→                value: Math.sqrt(3),
   240→                description: '边长为1的等边三角形高度'
   241→            },
   242→            {
   243→                symbol: '√5',
   244→                name: '平方根五',
   245→                nameEn: 'Square root of 5',
   246→                value: Math.sqrt(5),
   247→                description: '与黄金比例密切相关'
   248→            },
   249→            {
   250→                symbol: 'φ',
   251→                name: '黄金比例',
   252→                nameEn: 'Golden ratio',
   253→                value: (1 + Math.sqrt(5)) / 2,
   254→                description: '最美丽的比例，广泛存在于自然界'
   255→            },
   256→            {
   257→                symbol: '√[3]2',
   258→                name: '立方根二',
   259→                nameEn: 'Cube root of 2',
   260→                value: Math.cbrt(2),
   261→                description: '2的立方根'
   262→            },
   263→            {
   264→                symbol: 'γ',
   265→                name: '欧拉-马歇罗尼常数',
   266→                nameEn: 'Euler-Mascheroni',
   267→                value: 0.5772156649015329,
   268→                description: '调和级数与对数之差的极限'
   269→            },
   270→            {
   271→                symbol: 'δ',
   272→                name: '费根鲍姆常数',
   273→                nameEn: 'Feigenbaum constant',
   274→                value: 4.6692016091029,
   275→                description: '倍周期分岔的通用常数'
   276→            },
   277→            {
   278→                symbol: 'λ',
   279→                name: '康威常数',
   280→                nameEn: 'Conway constant',
   281→                value: 1.3035772690356,
   282→                description: '与字母序列变换相关'
   283→            },
   284→            {
   285→                symbol: 'Ω',
   286→                name: 'omega常数',
   287→                nameEn: 'Omega constant',
   288→                value: 0.5671432904097838,
