   295→                value: 1.202056903159594,
   296→                description: '黎曼ζ函数在3处的值'
   297→            },
   298→            {
   299→                symbol: '√(2π)',
   300→                name: '根号二π',
   301→                nameEn: 'Square root of 2π',
   302→                value: Math.sqrt(2 * Math.PI),
   303→                description: '高斯分布中的常数'
   304→            },
   305→            {
