   335→                name: '二倍根号二',
   336→                nameEn: 'Two square root of 2',
   337→                value: 2 * Math.SQRT2,
   338→                description: '2乘以√2'
   339→            },
   340→            {
   341→                symbol: 'π/2',
   342→                name: '二分之π',
   343→                nameEn: 'Pi over 2',
   344→                value: Math.PI / 2,
   345→                description: '圆周率的一半'
   346→            },
   347→            {
   348→                symbol: 'π²',
   349→                name: 'π的平方',
