   356→        let history = [];
   357→
   358→        function generate() {
   359→            const precision = parseInt(document.getElementById('precision').value);
   360→            const randomIndex = Math.floor(Math.random() * irrationals.length);
   361→            const selected = irrationals[randomIndex];
   362→
   363→            // 格式化数值
   364→            let formattedValue;
   365→            if (precision >= 100) {
   366→                // 大精度使用自定义格式化
   367→                formattedValue = formatHighPrecision(selected.value, precision);
   368→            } else {
   369→                formattedValue = selected.value.toFixed(precision);
   370→                // 移除尾随零
   371→                formattedValue = formattedValue.replace(/\.?0+$/, '');
   372→            }
   373→
   374→            // 更新显示
   375→            document.getElementById('symbol').textContent = selected.symbol;
   376→            document.getElementById('name').textContent = selected.name;
   377→            document.getElementById('value').textContent = formattedValue + '...';
   378→
   379→            // 添加到历史
   380→            addToHistory(selected);
   381→        }
   382→
   383→        function formatHighPrecision(value, precision) {
   384→            // 使用高精度计算
   385→            const multiplier = Math.pow(10, precision);
   386→            const scaled = BigInt(Math.floor(value * Number(BigInt(1) << BigInt(100)) * BigInt(multiplier))) / BigInt(1);
   387→            let result = scaled.toString();
   388→
   389→            // 插入小数点
   390→            if (result.length <= precision) {
   391→                result = '0.' + '0'.repeat(precision - result.length) + result;
   392→            } else {
   393→                result = result.slice(0, -precision) + '.' + result.slice(-precision);
   394→            }
   395→
   396→            return result;
   397→        }
   398→
   399→        function addToHistory(item) {
   400→            // 避免重复
   401→            if (!history.includes(item.symbol)) {
   402→                history.unshift(item.symbol);
   403→                if (history.length > 10) {
   404→                    history.pop();
   405→                }
   406→                updateHistoryDisplay();
   407→            }
   408→        }
   409→
   410→        function updateHistoryDisplay() {
   411→            const container = document.getElementById('historyList');
   412→            container.innerHTML = history.map(symbol =>
   413→                `<span class="history-item" onclick="showFromHistory('${symbol}')">${symbol}</span>`
   414→            ).join('');
   415→        }
   416→
   417→        function showFromHistory(symbol) {
   418→            const item = irrationals.find(i => i.symbol === symbol);
   419→            if (item) {
   420→                const precision = parseInt(document.getElementById('precision').value);
   421→                let formattedValue = item.value.toFixed(precision);
   422→                formattedValue = formattedValue.replace(/\.?0+$/, '');
   423→
   424→                document.getElementById('symbol').textContent = item.symbol;
   425→                document.getElementById('name').textContent = item.name;
   426→                document.getElementById('value').textContent = formattedValue + '...';
   427→            }
   428→        }
   429→
   430→        // 页面加载时生成一个随机无理数
   431→        generate();
   432→    </script>
   433→</body>
